import React, { useState, useEffect } from 'react';
import {
  APIProvider,
  Map,
  AdvancedMarker,
  Pin,
  InfoWindow,
  useMap
} from '@vis.gl/react-google-maps';
import { MarkerClusterer } from '@googlemaps/markerclusterer';

const defaultLocation = { lat: 10.8231, lng: 106.6297 };

const ClusteredMarkers = ({ markers, onMarkerClick }) => {
  const map = useMap();
  const [clusterer, setClusterer] = useState(null);
  const [markerRefs, setMarkerRefs] = useState({});

  useEffect(() => {
    if (!map) return;

    const cl = new MarkerClusterer({ map });
    setClusterer(cl);

    return () => {
      cl.clearMarkers();
    };
  }, [map]);

  useEffect(() => {
    if (!clusterer) return;

    clusterer.clearMarkers();
    clusterer.addMarkers(Object.values(markerRefs).filter(Boolean));
  }, [clusterer, markerRefs, markers]);

  const setMarkerRef = (marker, key) => {
    setMarkerRefs((prev) => {
      const existing = prev[key];

      if (marker && existing === marker) return prev;
      if (!marker && !existing) return prev;

      if (marker) {
        return { ...prev, [key]: marker };
      }

      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  return (
    <>
      {markers.map((marker) => (
        <AdvancedMarker
          key={marker.key}
          position={{ lat: marker.lat, lng: marker.lng }}
          ref={(ref) => setMarkerRef(ref, marker.key)}
          onClick={() => onMarkerClick(marker.data, marker.type)}
        >
          {marker.pin}
        </AdvancedMarker>
      ))}
    </>
  );
};

const MyLocationButton = ({ myLocation }) => {
  const map = useMap();

  if (!myLocation) return null;

  const handleClick = () => {
    if (!map) return;
    map.panTo(myLocation);
    map.setZoom(15);
  };

  return (
    <button
      onClick={handleClick}
      style={{
        position: 'absolute',
        top: '12px',
        right: '12px',
        zIndex: 10,
        background: '#2563EB',
        color: '#FFFFFF',
        border: 'none',
        borderRadius: '10px',
        padding: '10px 14px',
        fontSize: '14px',
        fontWeight: 600,
        cursor: 'pointer',
        boxShadow: '0 4px 12px rgba(0,0,0,0.15)'
      }}
    >
      Vị trí của tôi
    </button>
  );
};

const StormShieldMap = ({ shelters = [], reports = [], alerts = [] }) => {
  const [initialCenter, setInitialCenter] = useState(defaultLocation);
  const [myLocation, setMyLocation] = useState(null);
  const [selectedElement, setSelectedElement] = useState(null);

  useEffect(() => {
    if (!navigator.geolocation) {
      console.warn('Trình duyệt không hỗ trợ định vị.');
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        const loc = {
          lat: position.coords.latitude,
          lng: position.coords.longitude
        };

        setMyLocation(loc);
        setInitialCenter(loc);
      },
      () => {
        console.warn('Lỗi xác định vị trí. Dùng mặc định ở TP.HCM.');
      },
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
      }
    );
  }, []);

  const handleMarkerClick = (element, type) => {
    setSelectedElement({ ...element, elementType: type });
  };

  const allMarkers = [
    ...shelters
      .filter((s) => s.latitude != null && s.longitude != null)
      .map((s) => ({
        key: `s-${s.id}`,
        lat: s.latitude,
        lng: s.longitude,
        data: s,
        type: 'SHELTER',
        pin: (
          <Pin
            background={'#10B981'}
            borderColor={'#065F46'}
            glyphColor={'#FFFFFF'}
          />
        )
      })),
    ...reports
      .filter((r) => r.latitude != null && r.longitude != null)
      .map((r) => ({
        key: `r-${r.id}`,
        lat: r.latitude,
        lng: r.longitude,
        data: r,
        type: 'REPORT',
        pin: (
          <Pin
            background={'#F59E0B'}
            borderColor={'#92400E'}
            glyphColor={'#FFFFFF'}
          />
        )
      })),
    ...alerts
      .filter((a) => a.latitude != null && a.longitude != null)
      .map((a) => ({
        key: `a-${a.id}`,
        lat: a.latitude,
        lng: a.longitude,
        data: a,
        type: 'ALERT',
        pin: (
          <Pin
            background={'#EF4444'}
            borderColor={'#991B1B'}
            glyphColor={'#FFFFFF'}
          />
        )
      }))
  ];

  const infoPosition = selectedElement
    ? {
        lat: selectedElement.lat ?? selectedElement.latitude,
        lng: selectedElement.lng ?? selectedElement.longitude
      }
    : null;

  return (
    <div
      style={{
        position: 'relative',
        height: '500px',
        width: '100%',
        borderRadius: '12px',
        overflow: 'hidden',
        boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'
      }}
    >
      <APIProvider apiKey={process.env.REACT_APP_GOOGLE_MAPS_API_KEY}>
        <Map
          defaultZoom={13}
          defaultCenter={initialCenter}
          mapId="DEMO_MAP_ID"
          gestureHandling="greedy"
          disableDefaultUI={false}
        >
          <ClusteredMarkers markers={allMarkers} onMarkerClick={handleMarkerClick} />

          {myLocation && (
            <AdvancedMarker
              position={myLocation}
              onClick={() =>
                handleMarkerClick(
                  {
                    lat: myLocation.lat,
                    lng: myLocation.lng,
                    title: 'Bạn đang ở đây'
                  },
                  'USER'
                )
              }
            >
              <Pin
                background={'#2563EB'}
                borderColor={'#FFFFFF'}
                glyphColor={'#FFFFFF'}
              />
            </AdvancedMarker>
          )}

          <MyLocationButton myLocation={myLocation} />

          {selectedElement && infoPosition && (
            <InfoWindow
              position={infoPosition}
              onCloseClick={() => setSelectedElement(null)}
            >
              <div style={{ padding: '4px', maxWidth: '220px', lineHeight: 1.5 }}>
                {selectedElement.elementType === 'USER' && (
                  <strong style={{ color: '#2563EB' }}>
                    {selectedElement.title}
                  </strong>
                )}

                {selectedElement.elementType === 'SHELTER' && (
                  <div>
                    <strong style={{ color: '#10B981' }}>
                      {selectedElement.name}
                    </strong>
                    <br />
                    Địa chỉ: {selectedElement.address}
                    <br />
                    Trạng thái: {selectedElement.status}
                    <br />
                    Sức chứa: {selectedElement.currentOccupancy}/
                    {selectedElement.capacity}
                  </div>
                )}

                {selectedElement.elementType === 'REPORT' && (
                  <div>
                    <strong style={{ color: '#F59E0B' }}>
                      NGUY HIỂM: {selectedElement.reportType}
                    </strong>
                    <br />
                    Mức độ: {selectedElement.dangerLevel}
                    <br />
                    Chi tiết: {selectedElement.description}
                  </div>
                )}

                {selectedElement.elementType === 'ALERT' && (
                  <div>
                    <strong style={{ color: '#EF4444' }}>
                      CẢNH BÁO: {selectedElement.title}
                    </strong>
                    <br />
                    Mức độ: {selectedElement.severityLevel}
                    <br />
                    {selectedElement.description}
                  </div>
                )}
              </div>
            </InfoWindow>
          )}
        </Map>
      </APIProvider>
    </div>
  );
};

export default StormShieldMap;
